import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api';

const CATEGORIES = ['🛒 Покупки', '🚚 Переезд', '🔧 Ремонт', '🌿 Сад', '💻 IT помощь', '📷 Фото', '🎓 Обучение', '🐾 Животные'];

export default function CreateTask() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({
    title: '', description: '', category: '', payment: '',
    latitude: '', longitude: '', location_name: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!user) navigate('/signin');
  }, [user, navigate]);

  useEffect(() => {
    navigator.geolocation?.getCurrentPosition(pos => {
      setForm(f => ({
        ...f,
        latitude: pos.coords.latitude,
        longitude: pos.coords.longitude,
        location_name: 'Моё местоположение'
      }));
    });
  }, []);

  const handleChange = e => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.title) return setError('Введите название задачи');
    setError('');
    setLoading(true);
    try {
      const res = await api.post('/tasks', {
        ...form,
        payment: form.payment ? parseFloat(form.payment) : null,
        latitude: form.latitude ? parseFloat(form.latitude) : null,
        longitude: form.longitude ? parseFloat(form.longitude) : null,
      });
      navigate(`/tasks/${res.data.id}`);
    } catch (err) {
      setError(err.response?.data?.error || 'Ошибка создания задачи');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="app-container">
      <div className="page-header">
        <button className="back-btn" onClick={() => navigate(-1)}>← Назад</button>
        <span className="page-title">Создать задачу</span>
      </div>

      <div style={{ padding: '20px 20px 100px' }}>
        {error && <div className="error-msg">{error}</div>}

        <form onSubmit={handleSubmit}>
          <div className="input-group">
            <label>Название</label>
            <input
              name="title"
              placeholder="Например: Помочь с переездом"
              value={form.title}
              onChange={handleChange}
              required
            />
          </div>

          <div className="input-group">
            <label>Описание</label>
            <textarea
              name="description"
              placeholder="Подробно опиши что нужно сделать..."
              value={form.description}
              onChange={handleChange}
              rows={4}
            />
          </div>

          <div className="input-group">
            <label>Категория</label>
            <select name="category" value={form.category} onChange={handleChange}>
              <option value="">Выбрать категорию</option>
              {CATEGORIES.map(c => (
                <option key={c} value={c}>{c}</option>
              ))}
            </select>
          </div>

          <div className="input-group">
            <label>Локация</label>
            <input
              name="location_name"
              placeholder="Адрес или описание места"
              value={form.location_name}
              onChange={handleChange}
            />
          </div>

          {/* Map placeholder showing coords */}
          <div style={{
            background: '#e5e7eb', borderRadius: 14, height: 140,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            marginBottom: 16, position: 'relative', overflow: 'hidden'
          }}>
            {form.latitude ? (
              <div style={{ textAlign: 'center' }}>
                <div style={{ fontSize: 28 }}>📍</div>
                <div style={{ fontSize: 13, color: '#555', marginTop: 4 }}>
                  {parseFloat(form.latitude).toFixed(4)}, {parseFloat(form.longitude).toFixed(4)}
                </div>
                <div style={{ fontSize: 12, color: 'var(--green)', fontWeight: 600, marginTop: 4 }}>
                  Местоположение определено
                </div>
              </div>
            ) : (
              <div style={{ textAlign: 'center', color: '#999' }}>
                <div style={{ fontSize: 28 }}>🗺️</div>
                <div style={{ fontSize: 13, marginTop: 4 }}>MAP</div>
              </div>
            )}
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12, marginBottom: 16 }}>
            <div className="input-group" style={{ margin: 0 }}>
              <label>Широта</label>
              <input
                name="latitude" type="number" step="any"
                placeholder="43.2220"
                value={form.latitude}
                onChange={handleChange}
              />
            </div>
            <div className="input-group" style={{ margin: 0 }}>
              <label>Долгота</label>
              <input
                name="longitude" type="number" step="any"
                placeholder="76.8512"
                value={form.longitude}
                onChange={handleChange}
              />
            </div>
          </div>

          <div className="input-group">
            <label>Оплата (₸)</label>
            <input
              name="payment"
              type="number"
              placeholder="Сумма в тенге (необязательно)"
              value={form.payment}
              onChange={handleChange}
              min="0"
            />
          </div>

          <button type="submit" className="btn-primary" disabled={loading} style={{ marginTop: 8 }}>
            {loading ? 'Публикуем...' : 'Post Task'}
          </button>
        </form>
      </div>
    </div>
  );
}
